  "inlineSchema": "generator client {\n  provider = \"prisma-client\"\n  output   = \"./generated/prisma\"\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\") // Dodane standardowe zaciąganie URL (wymagane przez Prismę)\n  directUrl = env(\"DIRECT_URL\")\n}\n\nenum Role {\n  ADMIN\n  KREATOR\n  UCZESTNIK\n}\n\nmodel User {\n  id            String    @id @default(cuid())\n  name          String?\n  email         String?   @unique\n  password      String? // Pole na zahashowane hasło\n  emailVerified DateTime?\n  image         String?\n  role          Role      @default(UCZESTNIK)\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  accounts Account[]\n  sessions Session[]\n\n  // Relacje biznesowe\n  organizedMeetings Meeting[]     @relation(\"MeetingOrganizer\")\n  enrollments       Enrollment[]\n  certificates      Certificate[]\n}\n\nmodel Account {\n  id                String  @id @default(cuid())\n  userId            String\n  type              String\n  provider          String\n  providerAccountId String\n  refresh_token     String? @db.Text\n  access_token      String? @db.Text\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String? @db.Text\n  session_state     String?\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n}\n\n//MODUŁ A & B: CRM, LEADY, LEJKI SPRZEDAŻY\n\nenum LeadStatus {\n  NEW\n  CONTACTED\n  QUALIFIED\n  PROPOSAL\n  WON\n  LOST\n}\n\nmodel Lead {\n  id        String     @id @default(cuid())\n  firstName String\n  lastName  String?\n  email     String     @unique\n  phone     String?\n  status    LeadStatus @default(NEW) //Statusy leadów i pipeline\n  score     Int        @default(0) //Lead scoring\n  source    String? //Z jakiego lejka/formularza pochodzi\n  createdAt DateTime   @default(now())\n  updatedAt DateTime   @updatedAt\n\n  //Relacje\n  tags      Tag[]      @relation(\"LeadTags\")\n  notes     Note[]\n  documents Document[]\n  meetings  Meeting[]\n  messages  Message[]\n\n  // NOWE: Relacja do wartości Custom Fields\n  customFields LeadCustomFieldValue[]\n}\n\nmodel Tag {\n  id    String  @id @default(cuid())\n  name  String  @unique\n  color String? // NOWE: Opcjonalny kolor tła do wyświetlania w UI tabeli CRM\n\n  leads Lead[] @relation(\"LeadTags\")\n}\n\n// --- NOWE TABELE: CUSTOM FIELDS ---\n\nmodel CustomField {\n  id   String @id @default(cuid())\n  name String @unique // np. \"Wielkość firmy\", \"Budżet\"\n  type String // np. \"text\", \"number\", \"select\"\n\n  values LeadCustomFieldValue[]\n}\n\n// Tabela przechowująca konkretne wartości (np. Budżet -> \"50 000 PLN\" dla konkretnego Leada)\nmodel LeadCustomFieldValue {\n  id    String @id @default(cuid())\n  value String @db.Text // Wartość wpisana w formularzu (Text dla bezpieczeństwa długich wpisów)\n\n  leadId String\n  lead   Lead   @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  customFieldId String\n  customField   CustomField @relation(fields: [customFieldId], references: [id], onDelete: Cascade)\n\n  // Zabezpieczenie: dany Lead może mieć tylko jedną wartość dla konkretnego pola\n  @@unique([leadId, customFieldId])\n}\n\n// ----------------------------------\n\nmodel Note {\n  id        String   @id @default(cuid())\n  content   String   @db.Text\n  leadId    String\n  lead      Lead     @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n}\n\nmodel LandingPage {\n  id        String   @id @default(cuid())\n  title     String\n  slug      String   @unique //Do publikowania na domenie\n  htmlData  String?  @db.Text //Wygenerowany kod przez GrapesJS\n  cssData   String?  @db.Text\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n//MODUŁ C: KOMUNIKACJA (Email, SMS)\n\nmodel Message {\n  id        String   @id @default(cuid())\n  subject   String?\n  body      String   @db.Text\n  type      String //np. 'EMAIL'\n  direction String //'INBOUND' (od leada), 'OUTBOUND' (do leada)\n  leadId    String\n  lead      Lead     @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n}\n\n//MODUŁ D: KURSY I PORTAL CZŁONKOWSKI\n\nmodel Course {\n  id          String   @id @default(cuid())\n  title       String\n  description String?  @db.Text\n  price       Float?\n  isPublished Boolean  @default(false)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  modules     Module[]\n  enrollments Enrollment[]\n}\n\nmodel Module {\n  id       String   @id @default(cuid())\n  title    String\n  order    Int // Kolejność modułów\n  courseId String\n  course   Course   @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  lessons  Lesson[]\n}\n\nmodel Lesson {\n  id       String  @id @default(cuid())\n  title    String\n  videoUrl String? //Hostowanie wideo\n  content  String? @db.Text\n  order    Int\n  moduleId String\n  module   Module  @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n}\n\nmodel Enrollment {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  courseId  String\n  course    Course   @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  progress  Int      @default(0) // Procent ukończenia\n  createdAt DateTime @default(now())\n\n  @@unique([userId, courseId])\n}\n\nmodel Certificate {\n  id       String   @id @default(cuid())\n  userId   String\n  user     User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  title    String\n  issuedAt DateTime @default(now())\n}\n\n// ======================================================\n// MODUŁ E: DOKUMENTY I E-SIGNING\n// ======================================================\n\nmodel Document {\n  id        String    @id @default(cuid())\n  title     String\n  fileUrl   String // Ścieżka do zapisanego pliku PDF/HTML\n  isSigned  Boolean   @default(false)\n  signature String?   @db.Text // Plik graficzny z react-signature-canvas (base64)\n  signedAt  DateTime?\n\n  leadId String\n  lead   Lead   @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n}\n\n// MODUŁ F: KALENDARZ I SPOTKANIA\n\nmodel Meeting {\n  id        String   @id @default(cuid())\n  title     String\n  startTime DateTime // Format UTC\n  endTime   DateTime\n  meetLink  String? // Wirtualny pokój, np. Zoom/Meet\n\n  organizerId String\n  organizer   User   @relation(\"MeetingOrganizer\", fields: [organizerId], references: [id])\n\n  leadId String?\n  lead   Lead?   @relation(fields: [leadId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n",
